import{c as t,Q as o,j as a,m as n}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse(`{"title":"Ben's Bites — 2026-04-16","description":"","frontmatter":{"title":"Ben's Bites — 2026-04-16","date":"2026-04-16T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-16-bens-bites.md","filePath":"research/ai-news/2026-04/2026-04-16-bens-bites.md","lastUpdated":1779796674000}`),r={name:"research/ai-news/2026-04/2026-04-16-bens-bites.md"};function s(i,e,l,u,p,c){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="🍔-ben-s-bites-—-2026-04-16" tabindex="-1">🍔 Ben&#39;s Bites — 2026-04-16 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-04-16" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-04-16&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="my-cheatsheet-for-a-clean-context" tabindex="-1"><a href="https://www.bensbites.com/p/my-cheatsheet-for-a-clean-context" target="_blank" rel="noreferrer">My cheatsheet for a clean context</a> <a class="header-anchor" href="#my-cheatsheet-for-a-clean-context" aria-label="Permalink to &quot;[My cheatsheet for a clean context](https://www.bensbites.com/p/my-cheatsheet-for-a-clean-context)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-04-16</em></p><p>Hey folks</p><p>Boarding my flight to SF very shortly, and I got an email to let me know - no WiFi today. Uh oh. I was kinda hoping my 11 hours uninterrupted hours without the kids would be productive for once (I’m usually a very OOO long-hauler, no internet). But I still have some work to polish this talk I’m giving on Tuesday.</p><p>I’m also in town looking to deploy $100k cheques to dev tools and infra founders, plus see some of my wonderful LPs and meeting new ones. Ben’s Bites Fund II has already started investing.</p><p>So my flight… I’ve had to hurriedly download a few local models so I can use my agents offline and I think, so far, Gemma 4: 26b is going to be my choice.</p><p>We’re so spoiled today with fast intelligence at our fingertips and it’s funny how used to the new intelligence levels we get</p><p>Local models are slow to boot up (you’ve got to be more mindful of what context is being loaded on startup (so I’m running with no-skills to get it to go faster, I can call the skills when I want — maybe I’d actually prefer to do that generally 🤔). And they feel pretty slow to do work, but only because of said spoils.</p><p>I’ve been in the weeds of context management recently because of the course I’m working on. And it’s been useful to just remind myself about how prickly it can be;</p><p>If an agent runs web searches - presumably you didn’t read them, its gobbling up context from content you do not know is 1. right, 2. not ai-slop, and 3. by a source you’d recommend.</p><p>Little (or big) lines of slop, misdirection, misinformation slip in to the context and compound over time</p><p>Reaching ~60% of a context window is probably the limit of where you want to be</p><p>Use other sessions as context-gathering sessions, if there’s lots of documents then create one summary file with the information (and try to read or at least skim it! - I am trying, promise)</p><p>I don’t trust 1M context windows, there’s a great post by Thariq from Anthropic below about this window. I shouldn’t need my context for my tasks to need perfect recall beyond ~150k tokens, that’s a lot of words. Only until 1M context windows are the norm, the models dont forget anything and help clean polluted context along the way!</p><p>Anyway, got to head to the gate! This was a little different of an intro, let me know if you liked it. I need to share more as I’m learning (or diving deeper).</p><p>Ben’s Bites is brought to you by <a href="https://attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter_sponsorship&amp;utm_campaign=bens_bites-Y26" target="_blank" rel="noreferrer">Attio</a>, the AI CRM</p><p>Honestly, no one gets excited about a CRM. But then they try <a href="https://attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter_sponsorship&amp;utm_campaign=bens_bites-Y26" target="_blank" rel="noreferrer">Attio</a>. It connects to Claude Code and n8n through its MCP server, completely bridging the gap between my customer data and apps. Wait, there&#39;s more, like flagging churn risk and turning customer feedback into Linear projects. <a href="https://attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter_sponsorship&amp;utm_campaign=bens_bites-Y26" target="_blank" rel="noreferrer">Try it now</a>.</p><p>Headlines</p><p><a href="https://claude.com/blog/claude-code-desktop-redesign" target="_blank" rel="noreferrer">Claude Code’s desktop got a redesign</a>. Brings many CLI-only features and more (like split windows for multiple sessions) to the desktop app. Big improvement, but still a lot is missing. It picks up some CLI sessions but not all, opening/editing files isn’t obvious, and it keeps asking for permission even with “bypass” settings on.</p><p><a href="https://blog.google/innovation-and-ai/products/gemini-app/gemini-app-now-on-mac-os/" target="_blank" rel="noreferrer">Gemini also has a native Mac app now</a>. But it’s light on features - no Gems, no notebooks - and the design feels rough to say the least.</p><p>New models - <a href="https://openai.com/index/scaling-trusted-access-for-cyber-defense/" target="_blank" rel="noreferrer">GPT-5.4-Cyber</a> from OpenAI, fine-tuned for cybersecurity, with <a href="https://openai.com/index/accelerating-cyber-defense-ecosystem/" target="_blank" rel="noreferrer">limited access</a> to trusted partners. And <a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-3-1-flash-tts/" target="_blank" rel="noreferrer">Gemini 3.1 Flash TTS</a> from Google - better voices, audio tags for controlling tone and pacing, and 70 languages.</p><p><a href="https://claude.com/blog/introducing-routines-in-claude-code" target="_blank" rel="noreferrer">Routines</a> in Claude Code are now in research preview - set up a prompt, a repo, and your connectors once, then run it on a schedule (or via API/GitHub trigger). Runs on Anthropic’s infra, so you don’t need your laptop open. Basically, extended cron jobs. OpenClaw calls these heartbeats.</p><p>With the latest update to <a href="https://x.com/OpenAIDevs/status/2044466699785920937" target="_blank" rel="noreferrer">OpenAI’s Agents SDK</a>, you can run Codex-style agents in production without building the whole harness yourself. You get sandboxed execution, computer-use, skills, memory, and compaction built in.</p><p>Most RAG systems return wrong answers with complete confidence. Gauntlet&#39;s free Night School covers how production AI engineers actually fix that — setup, evaluation, the full loop. Wednesday, April 22. <a href="https://us06web.zoom.us/webinar/register/2017762003233/WN_P79TrYY5R8Cru6xEDkwKcw" target="_blank" rel="noreferrer">Register free</a>*</p><p>My feed</p><p><a href="https://blog.google/products-and-platforms/products/chrome/skills-in-chrome/" target="_blank" rel="noreferrer">Skills in Chrome</a> let you save prompts as reusable one-click workflows that run on whatever page you’re viewing.</p><p><a href="https://x.com/cursor_ai/status/2044486585492947010" target="_blank" rel="noreferrer">Cursor</a> can now respond with interactive canvases - dashboards and custom interfaces instead of just text.</p><p><a href="https://x.com/zenorocha/status/2044055463067824256" target="_blank" rel="noreferrer">Resend</a> shipped a new email editor with BYOA (bring your own agent). There’s a built-in LLM, but you can also MCP into the editor with your own setup.</p><p><a href="https://x.com/danshipper/status/2044079255726838273" target="_blank" rel="noreferrer">Sparkle v4</a> from Every - let AI organise your filesystem like you would.</p><p><a href="https://x.com/dvassallo/status/2044088256753799567" target="_blank" rel="noreferrer">Daniel</a> pointed an agent at 5 years of home-building emails (511 events, 690 documents, 170 finance records) and got back a full project timeline in ~$500 of Opus tokens.</p><p><a href="https://x.com/pbakaus/status/2044505743144194514" target="_blank" rel="noreferrer">Impeccable v2</a> - the design skill for coding agents. v2 adds a CLI scanner (works without an LLM), a Chrome extension, and a /shape command that runs a design interview before writing any code.</p><p><a href="https://claude.com/blog/using-claude-code-session-management-and-1m-context" target="_blank" rel="noreferrer">Using Claude Code</a> - guide on session management, compaction, and the 1M context window.</p><p>30 min tutorial on <a href="https://www.youtube.com/watch?v=kF2WQgk1LtY" target="_blank" rel="noreferrer">building software with agents</a> in Cursor.</p><p><a href="https://x.com/Altimor/status/2044108104816832576" target="_blank" rel="noreferrer">Lindy AI’s founder</a> says GLM 5.1 will likely become their default over closed-source models for most use cases, saving them a bunch on inference (their biggest cost, more than payroll).</p><p>OpenRouter now offers <a href="https://x.com/alexatallah/status/2044500778086228278" target="_blank" rel="noreferrer">video generation models with one universal API</a> across all video models.</p><p><a href="https://techcommunity.microsoft.com/blog/microsoft365copilotblog/copilot-in-word-new-capabilities-for-document-workflows/4508974" target="_blank" rel="noreferrer">Copilot in Word</a> now tracks changes and leaves comments.</p><p><a href="https://windsurf.com/blog/windsurf-2-0" target="_blank" rel="noreferrer">Windsurf 2.0</a> - Manage all your agents from one place and delegate work to the cloud with Devin.</p><p><a href="https://x.com/kwindla/status/2044106314612408437" target="_blank" rel="noreferrer">Gradient Bang</a> - a fun multiplayer game with subagents in space. Built with Pipecat, Supabase, and open-source.</p><p>Afters</p><p>#CHI2026 &quot;,&quot;username&quot;:&quot;GoogleResearch&quot;,&quot;name&quot;:&quot;Google Research&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/1929964199956062208/Cv3ZuT1w_normal.jpg%22,%22date%22:%222026-04-15T06:40:18.000Z%22,%22photos%22:%5B%7B%22img_url%22:%22https://res.cloudinary.com/hhsslviub/video/upload/e_loop,vs_40/z3zualhklx0prnwc3dra.gif%22,%22link_url%22:%22https://t.co/SpKfhheBOl%22%7D%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:125,%22retweet_count%22:618,%22like_count%22:4724,%22impression_count%22:770326,%22expanded_url%22:null,%22video_url%22:null,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/1929964199956062208/Cv3ZuT1w_normal.jpg&quot;,&quot;date&quot;:&quot;2026-04-15T06:40:18.000Z&quot;,&quot;photos&quot;:[{&quot;img_url&quot;:&quot;https://res.cloudinary.com/hhsslviub/video/upload/e_loop,vs_40/z3zualhklx0prnwc3dra.gif&quot;,&quot;link_url&quot;:&quot;https://t.co/SpKfhheBOl&quot;}],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:125,&quot;retweet_count&quot;:618,&quot;like_count&quot;:4724,&quot;impression_count&quot;:770326,&quot;expanded_url&quot;:null,&quot;video_url&quot;:null,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>@0interestrates of @juliusai.\\n\\nWe talk about:\\n\\n How Rahul ended up solo\\n The football analogy for building momentum\\n Why 8/10 co-founder teams are fighting &quot;,&quot;username&quot;:&quot;julianweisser&quot;,&quot;name&quot;:&quot;weisser&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/2028707427659714560/FqyCcqmK_normal.jpg%22,%22date%22:%222026-04-15T18:28:28.000Z%22,%22photos%22:%5B%7B%22img_url%22:%22https://substackcdn.com/image/upload/w_1028,c_limit,q_auto:best/l_twitter_play_button_rvaygk,w_88/ruck1ztzbpwmxyfmjhne%22,%22link_url%22:%22https://t.co/RRuwPXkm3p%22%7D%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:11,%22retweet_count%22:13,%22like_count%22:121,%22impression_count%22:32330,%22expanded_url%22:null,%22video_url%22:%22https://video.twimg.com/amplify_video/2044480254887235584/vid/avc1/1280x720/tiKeSYYO8hwy2ZkY.mp4%22,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/2028707427659714560/FqyCcqmK_normal.jpg&quot;,&quot;date&quot;:&quot;2026-04-15T18:28:28.000Z&quot;,&quot;photos&quot;:[{&quot;img_url&quot;:&quot;https://substackcdn.com/image/upload/w_1028,c_limit,q_auto:best/l_twitter_play_button_rvaygk,w_88/ruck1ztzbpwmxyfmjhne&quot;,&quot;link_url&quot;:&quot;https://t.co/RRuwPXkm3p&quot;}],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:11,&quot;retweet_count&quot;:13,&quot;like_count&quot;:121,&quot;impression_count&quot;:32330,&quot;expanded_url&quot;:null,&quot;video_url&quot;:&quot;https://video.twimg.com/amplify_video/2044480254887235584/vid/avc1/1280x720/tiKeSYYO8hwy2ZkY.mp4&quot;,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben’s Bites</p><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p><ul><li>sponsors who make this newsletter possible 😃</li></ul><p>Wanna partner with us for the next quarter?</p><p>Email us at <a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></p><hr>',51)])])}const m=t(r,[["render",s]]);export{d as __pageData,m as default};
